bool VisitFunctionDecl(FunctionDecl* decl) {
  if (CanIgnoreCurrentASTNode())
    return true;
  // If a function declaration specifies default arguments but not for
  // the last parameters, like this:
  // void Fn(int = 0, int);
  // there should be (a) prior declaration(s) that specifies default argument
  // values for the last parameters.
  for (unsigned i = 1, ie = decl->getNumParams(); i < ie; ++i) {
    if (IsDefArgSpecified(i - 1, decl) && !IsDefArgSpecified(i, decl)) {
      // There should be a fn redecl specifying the i-th param default value.
      for (const FunctionDecl* redecl : decl->redecls()) {
        if (IsDefArgSpecified(i, redecl)) {
          ReportDeclUse(CurrentLoc(), redecl, nullptr, UF_RedeclUse);
          return Base::VisitFunctionDecl(decl);
        }
      }
    }
  }
  return Base::VisitFunctionDecl(decl);
}

// Avoid forward-declaration warnings for types which _should_ be already
// provided by the primary method declaration. For example,
// for 'struct Derived : public Base { T1 method(const T2&); };', T1 and T2
// are provided by Base, and should not be forward-decl reported in Derived.
bool TraverseCXXMethodDecl(CXXMethodDecl* method_decl) {
  if (CanIgnoreCurrentASTNode())
    return true;

  if (!method_decl->size_overridden_methods())
    return Base::TraverseCXXMethodDecl(method_decl);

  set<const Decl*> fwd_blocked = blocked_for_fwd_decl_;
  auto add_canonical_components = [&fwd_blocked](QualType part) {
    for (const Type* type : GetCanonicalComponentsOfType(part.getTypePtr())) {
      if (const Decl* decl = TypeToDeclAsWritten(type)) {
        // For templates, retrieve primary template declaration so as to match
        // what VisitTemplateSpecializationType does.
        if (const auto* spc = dyn_cast<ClassTemplateSpecializationDecl>(decl))
          decl = spc->getSpecializedTemplate();
        fwd_blocked.insert(decl->getCanonicalDecl());
      }
    }
  };
  add_canonical_components(method_decl->getReturnType());
  for (const ParmVarDecl* param : method_decl->parameters())
    add_canonical_components(param->getType());

  ValueSaver<set<const Decl*>> blocked_fwd_decl_guard =
      ScopedAdditionalBlockedForFwdDecl(fwd_blocked);
  // Full type info suggestions are blocked in CanBeProvidedTypeComponent.
  return Base::TraverseCXXMethodDecl(method_decl);
}

